external_knowledge:
- "Veterans" refer to players who finished their careers at least 5 years ago;
- "Exceptional batting skills" in this context means achieving a strike rate greater than 100 in any match;
- "Best bowling stats" refer to the player's best bowling figures recorded.

- 'ancient duels' metaphorically refers to matches;
- 'span of a generation' is interpreted as more than 30 years;
- 'clashed in the realm of One Day Internationals' means matches of type 'ODI';
- 'identities' refer to the names of the teams and their match IDs.

sql:
SELECT best_bowling_figures 
FROM player_profiles 
WHERE total_runs_scored > 2000;

SELECT match_id, result
FROM matches
WHERE team1_id = 1;

SELECT player_id, match_id, overs, maidens, runs, wickets
FROM player_performance
WHERE overs > 5;

SELECT profile_id, player_id 
FROM player_profiles 
ORDER BY total_runs_scored DESC;

SELECT p.player_id, pp.total_matches_played AS 'Shadow on the Field'
FROM players p
INNER JOIN player_profiles pp ON p.player_id = pp.player_id;

